const removeButton=document.getElementById("remove-account"),apiBaseUrl=document.documentElement.dataset.apiBaseUrl.replace(/\/$/,"");removeButton.addEventListener("click",async function(){if(!apiBaseUrl){alert("Everpublich VM API is not configured yet.");return}confirm("Remove this Everpublich account?")&&(await fetch(apiBaseUrl+"/api/remove-account",{method:"POST",headers:{"content-type":"application/json",authorization:"Bearer "+(localStorage.getItem("everpublich_admin_token")||"")},body:JSON.stringify({user_id:localStorage.getItem("everpublich_user_id")})}),localStorage.removeItem("everpublich_admin_token"),localStorage.removeItem("everpublich_user_id"),location.href="index.html")});
